import { useState, useEffect } from "react";
import { Link, useLocation } from "react-router-dom";
import { useAuth } from "../context/AuthContext";
import "../App.css";

export default function Nav() {
  const [darkMode, setDarkMode] = useState(false);
  const location = useLocation();

  const { user, logout, loading } = useAuth();

  /* =============================
      THEME SYSTEM
  ============================= */
  const applyTheme = (mode) => {
    const body = document.body;
    if (mode === "dark") {
      body.classList.add("dark-mode");
      localStorage.setItem("user-theme", "dark");
    } else {
      body.classList.remove("dark-mode");
      localStorage.setItem("user-theme", "light");
    }
    window.dispatchEvent(new Event("storage"));
  };

  useEffect(() => {
    const savedTheme = localStorage.getItem("user-theme");
    const systemPrefersDark = window.matchMedia("(prefers-color-scheme: dark)").matches;

    if (savedTheme === "dark") applyTheme("dark");
    else if (savedTheme === "light") applyTheme("light");
    else applyTheme(systemPrefersDark ? "dark" : "light");
  }, []);

  const toggleTheme = () => {
    setDarkMode(prev => !prev);
    const isDark = document.body.classList.contains("dark-mode");
    applyTheme(isDark ? "light" : "dark");
  };

  const isActive = (path) => location.pathname === path ? "active" : "";

  /* =============================
      FIX: WAIT FOR AUTH LOAD
  ============================= */
  if (loading) return null;

  const isUser = user?.role === "user";
  const isAdmin = user?.role === "admin";

  return (
    <header>
      <h1 className="title">
        Expressing Creativity Through Art and Crafts
      </h1>

      <nav className="menu">

        {/* ================= COMMON ================= */}
        <Link to="/home" className={isActive("/home")}>HOME</Link>
        <Link to="/about" className={isActive("/about")}>ABOUT</Link>
        <Link to="/contact" className={isActive("/contact")}>CONTACT US</Link>

        {/* ================= GUEST ================= */}
        {!user && (
          <>
            <Link to="/login" className={isActive("/login")}>LOGIN</Link>
            <Link to="/register" className={isActive("/register")}>REGISTER</Link>
          </>
        )}

        {/* ================= USER ================= */}
        {isUser && (
          <>
            <Link to="/home" className={isActive("/home")}>FEED</Link>
            <Link to="/create-post" className={isActive("/create-post")}>CREATE POST</Link>
            <Link to="/profile" className={isActive("/profile")}>PROFILE</Link>

            <button onClick={logout}>LOGOUT</button>
          </>
        )}

        {/* ================= ADMIN ================= */}
        {isAdmin && (
          <>
            <Link to="/admin" className={isActive("/admin")}>DASHBOARD</Link>
            <Link to="/manage-users" className={isActive("/manage-users")}>USERS</Link>
            <Link to="/manage-posts" className={isActive("/manage-posts")}>POSTS</Link>

            <button onClick={logout}>LOGOUT</button>
          </>
        )}

        {/* ================= THEME ================= */}
        <button className="theme-btn" onClick={toggleTheme}>
          ☀️ 🌙
        </button>

      </nav>
    </header>
  );
}
